#include <stdio.h>
#include <stdint.h>

int64_t calculateW(int64_t* arr, int n) {
    if (n == 0) return 0;
    if (n == 1) return arr[0];
    if (n == 2) return (arr[0] ^ arr[1]) - 1;
    // find two elements that are congruent modulo the highest possible power of 2
    int64_t maxPower = 0;
    while ((1LL << (maxPower + 1)) <= arr[0]) maxPower++;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            if ((arr[i] & ((1LL << maxPower) - 1)) == (arr[j] & ((1LL << maxPower) - 1))) {
                int64_t a = arr[i], b = arr[j];
                int64_t* newArr = (int64_t*)malloc((n - 2) * sizeof(int64_t));
                int k = 0;
                for (int l = 0; l < n; l++) {
                    if (l != i && l != j) newArr[k++] = arr[l];
                }
                return (a ^ b) - 1 ^ calculateW(newArr, n - 2);
            }
        }
    }
    return -1; // should not reach here
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int64_t* arr = (int64_t*)malloc(N * sizeof(int64_t));
        for (int i = 0; i < N; i++) scanf("%lld", &arr[i]);
        for (int i = 0; i < N; i++) {
            int64_t* newArr = (int64_t*)malloc((N - 1) * sizeof(int64_t));
            int k = 0;
            for (int j = 0; j < N; j++) {
                if (j != i) newArr[k++] = arr[j];
            }
            printf("%lld ", calculateW(newArr, N - 1));
            free(newArr);
        }
        printf("\n");
        free(arr);
    }
    return 0;
}

